import{f as a,g as n,J as s}from"./common-03e46d7f.js";const e='{"title":"Electron基础及常用到的点","frontmatter":{"date":"2023-08-01","title":"Electron基础及常用到的点","tags":["work"],"describe":"electron-start"},"headers":[{"level":2,"title":"介绍","slug":"介绍"},{"level":2,"title":"Electron 中的流程","slug":"electron-中的流程"},{"level":3,"title":"主进程","slug":"主进程"},{"level":3,"title":"渲染进程","slug":"渲染进程"},{"level":3,"title":"Preload 脚本","slug":"preload-脚本"},{"level":3,"title":"进程间通信 IPC","slug":"进程间通信-ipc"},{"level":2,"title":"打包","slug":"打包"},{"level":3,"title":"package","slug":"package"},{"level":3,"title":"make","slug":"make"},{"level":3,"title":"publish","slug":"publish"},{"level":2,"title":"为什么主进程到渲染进程没有双向通信","slug":"为什么主进程到渲染进程没有双向通信"}],"relativePath":"docs/electron/electron-start.md","lastUpdated":1706144232620.6472}';var p={};const t=[s('<h2 id="介绍"><a class="header-anchor" href="#介绍" aria-hidden="true">#</a> 介绍</h2><p>Electron 是一个使用 JavaScript、HTML 和 CSS 构建桌面应用程序的框架。Electron 将 Chromium 和 Node.js 嵌入到了一个二进制文件中，并且集成了跨平台的 Native 方案，使得同一个项目可以打包成不同的原生应用。</p><h2 id="electron-中的流程"><a class="header-anchor" href="#electron-中的流程" aria-hidden="true">#</a> Electron 中的流程</h2><p>Electron 继承 Chromium 的多进程架构，Chrome 页签、扩展等都有自己的渲染进程，避免单进程崩溃不影响整个浏览器，浏览器控制这些标签页的渲染进程，以及整个应用程序的生命周期。</p><p>Electron 类似于上述 Chrome 的架构，包含主进程和渲染进程，类似于 Chrome 的浏览器和渲染进程。</p><h3 id="主进程"><a class="header-anchor" href="#主进程" aria-hidden="true">#</a> 主进程</h3><p>每个 Electron 应用都有一个单一的主进程，作为应用程序的入口。主进程运行在 Node 环境，可以调用任何 node 模块、操作本地文件等。</p><h4 id="窗口管理"><a class="header-anchor" href="#窗口管理" aria-hidden="true">#</a> 窗口管理</h4><p>主进程的主要目的是使用 <a href="https://www.electronjs.org/zh/docs/latest/api/browser-window" target="_blank" rel="noopener noreferrer">BrowserWindow</a> 模块创建和管理应用程序窗口。</p><p>可以在主进程中通过 window 的 <a href="https://www.electronjs.org/zh/docs/latest/api/web-contents" target="_blank" rel="noopener noreferrer">webContent</a> 对象与网页内容进行交互。</p><div class="language-js"><pre><code><span class="token keyword">const</span> <span class="token punctuation">{</span> BrowserWindow <span class="token punctuation">}</span> <span class="token operator">=</span> <span class="token function">require</span><span class="token punctuation">(</span><span class="token string">&#39;electron&#39;</span><span class="token punctuation">)</span>\n\n<span class="token keyword">const</span> win <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token class-name">BrowserWindow</span><span class="token punctuation">(</span><span class="token punctuation">{</span> <span class="token literal-property property">width</span><span class="token operator">:</span> <span class="token number">800</span><span class="token punctuation">,</span> <span class="token literal-property property">height</span><span class="token operator">:</span> <span class="token number">1500</span> <span class="token punctuation">}</span><span class="token punctuation">)</span>\nwin<span class="token punctuation">.</span><span class="token function">loadURL</span><span class="token punctuation">(</span><span class="token string">&#39;https://github.com&#39;</span><span class="token punctuation">)</span>\n\n<span class="token keyword">const</span> contents <span class="token operator">=</span> win<span class="token punctuation">.</span>webContents\nconsole<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span>contents<span class="token punctuation">)</span>\n</code></pre></div><h4 id="应用程序生命周期"><a class="header-anchor" href="#应用程序生命周期" aria-hidden="true">#</a> 应用程序生命周期</h4><p>主进程可以通过 Electron 的 <a href="https://www.electronjs.org/zh/docs/latest/api/app" target="_blank" rel="noopener noreferrer">app</a> 模块控制当前应用程序的生命周期。</p><div class="language-js"><pre><code><span class="token keyword">const</span> <span class="token punctuation">{</span> app <span class="token punctuation">}</span> <span class="token operator">=</span> <span class="token function">require</span><span class="token punctuation">(</span><span class="token string">&#39;electron&#39;</span><span class="token punctuation">)</span>\n<span class="token comment">// 在最后一个窗口被关闭时退出应用</span>\napp<span class="token punctuation">.</span><span class="token function">on</span><span class="token punctuation">(</span><span class="token string">&#39;window-all-closed&#39;</span><span class="token punctuation">,</span> <span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token operator">=&gt;</span> <span class="token punctuation">{</span>\n  <span class="token keyword">if</span> <span class="token punctuation">(</span>process<span class="token punctuation">.</span>platform <span class="token operator">!==</span> <span class="token string">&#39;darwin&#39;</span><span class="token punctuation">)</span> app<span class="token punctuation">.</span><span class="token function">quit</span><span class="token punctuation">(</span><span class="token punctuation">)</span>\n<span class="token punctuation">}</span><span class="token punctuation">)</span>\n</code></pre></div><ul><li>ready 当 Electron 完成初始化时，发出一次</li><li>window-all-closed 当所有窗口都被关闭时触发</li><li>quit 在应用程序退出时发出</li><li>activate 当应用程序被激活时触发</li></ul><h4 id="原声-api"><a class="header-anchor" href="#原声-api" aria-hidden="true">#</a> 原声 API</h4><p>为了使 Electron 的功能不仅仅限于对网页内容的封装，主进程也添加了自定义的 API 来与用户的作业系统进行交互。 Electron 有着多种控制原生桌面功能的模块，例如菜单、对话框以及托盘图标。</p><h3 id="渲染进程"><a class="header-anchor" href="#渲染进程" aria-hidden="true">#</a> 渲染进程</h3><p>通过 BrowserWindow 打开的页面都是一个渲染进程，不能使用 Node 相关的 API 和模块。</p><h3 id="preload-脚本"><a class="header-anchor" href="#preload-脚本" aria-hidden="true">#</a> Preload 脚本</h3><p>使主进程和渲染进程桥接在一起。</p><p>在渲染进程加载之前执行的脚本，可以访问 Node.js API，并且可以访问 Window 对象，通过 Preload 脚本在全局 window 中暴露任意 API，在渲染进程中使用。</p><p>由于安全问题，在 Preload 脚本中直接设置<code>window.xxx = &#39;xxx&#39;</code>时，获取到的<code>window.xxx</code>是 undefined，需要通过 <a href="https://www.electronjs.org/zh/docs/latest/api/context-bridge" target="_blank" rel="noopener noreferrer">contextBridge</a> 来实现交互。</p><div class="language-js"><pre><code><span class="token comment">// preload.js</span>\n<span class="token keyword">const</span> <span class="token punctuation">{</span> contextBridge <span class="token punctuation">}</span> <span class="token operator">=</span> <span class="token function">require</span><span class="token punctuation">(</span><span class="token string">&#39;electron&#39;</span><span class="token punctuation">)</span>\n\ncontextBridge<span class="token punctuation">.</span><span class="token function">exposeInMainWorld</span><span class="token punctuation">(</span><span class="token string">&#39;IS_MAC&#39;</span><span class="token punctuation">,</span> process<span class="token punctuation">.</span>platform <span class="token operator">===</span> <span class="token string">&#39;darwin&#39;</span><span class="token punctuation">)</span>\n</code></pre></div><p>在渲染进程中，就可以使用<code>window.IS_MAC</code>来判断环境。</p><h3 id="进程间通信-ipc"><a class="header-anchor" href="#进程间通信-ipc" aria-hidden="true">#</a> 进程间通信 IPC</h3><p>主进程和渲染进程各司其职，意味着主进程没法访问 DOM 元素，渲染进程无法访问 Node.js API。</p><p>使用进程间通信 IPC 可以解决。Electron 提供 ipcMain（从主进程到渲染进程的异步通信） 模块和 ipcRenderer（从渲染器进程到主进程的异步通信） 模块实现 IPC 以在两种进程之间传输任意信息，例如从 UI 调用原生 API 或从原生菜单触发 Web 内容的更改。</p><h4 id="渲染进程到主进程"><a class="header-anchor" href="#渲染进程到主进程" aria-hidden="true">#</a> 渲染进程到主进程</h4><p>实现在渲染进程中调用主进程的 API，渲染进程中使用 ipcRenderer.send 发送消息，在主进程中使用 ipcMain.on 接收消息</p><h4 id="主进程到渲染进程"><a class="header-anchor" href="#主进程到渲染进程" aria-hidden="true">#</a> 主进程到渲染进程</h4><h2 id="打包"><a class="header-anchor" href="#打包" aria-hidden="true">#</a> 打包</h2><p>electron-forge 构建步骤：package、make、publish</p><p>依赖前一个输出结果：publish 依赖 make、make 依赖 package</p><p><img src="/blog/_assets/electron-pmp.84411272.png" alt="electron-pmp.png"></p><h3 id="package"><a class="header-anchor" href="#package" aria-hidden="true">#</a> package</h3><p>将 electron 应用打包为特定平台的可执行包，例如（windows 上的.exe，mac 上的.app，M1M2 芯片的.dmg），会打包到/out/文件夹中，<code>--arch</code>代表要打包的目标架构</p><div class="language-bash"><pre><code>electron-forge package --arch<span class="token operator">=</span>arm64\nelectron-forge package --arch<span class="token operator">=</span>x64\n</code></pre></div><p>需要处理：</p><ol><li>macOS 上应用程序分发有两层安全技术：<code>代码签名</code>和<code>公证</code></li></ol><ul><li><p>代码签名</p><p>是一种安全技术，用于证明应用程序是本人创建</p></li><li><p>公证</p></li></ul><h3 id="make"><a class="header-anchor" href="#make" aria-hidden="true">#</a> make</h3><p>将通过 forge 配置和传入的参数，为 electron 应用制作可分发文件</p><p>可执行包（Executable Package）：通过 Electron 打包工具构建的最终应用程序。通常是一个可执行文件（如 .exe、.app 或 .dmg 文件），可直接运行。这个可执行包包含了应用的源代码、依赖库、资源文件等一切必要的内容，以便用户能够在其计算机上运行应用。</p><p>分发包（Distribution Package）：将可执行包分发给最终用户的打包版本。分发包可能包含了额外的文件，如安装向导、许可协议、应用图标等。它的目的是将应用程序交付给最终用户，以便他们能够方便地安装和使用你的应用。</p><p>总结起来，可执行包是你实际构建的应用程序，而分发包是包含了可执行包及其他用于分发和展示的资源的打包版本。分发包可以用于在不同平台上分发你的应用，并确保用户能够顺利安装和使用它。</p><h3 id="publish"><a class="header-anchor" href="#publish" aria-hidden="true">#</a> publish</h3><p>执行 package 打包，执行 make 制作 Forge 应用程序并将其发布到 Forge 配置中定义的发布目标。</p><h2 id="为什么主进程到渲染进程没有双向通信"><a class="header-anchor" href="#为什么主进程到渲染进程没有双向通信" aria-hidden="true">#</a> 为什么主进程到渲染进程没有双向通信</h2><p>Electron 选择了一种主进程到渲染进程单向通信的架构，主要基于以下原因：</p><p>安全性和隔离：渲染进程通常运行应用程序的界面部分，而主进程则处理底层系统交互。将主进程到渲染进程的通信限制为单向可以更好地隔离不同层次的操作，防止渲染进程直接访问可能会影响系统稳定性和安全性的功能。</p><p>控制和稳定性： 将主进程作为中心控制点可以更好地管理应用程序的整体状态。如果允许主进程直接访问渲染进程，可能会导致难以预测的交互，从而影响应用程序的稳定性。</p><p>开发者体验： 限制通信方向可以简化通信模型，使开发者更容易理解和处理通信。如果允许双向通信，可能会引入更多的复杂性，增加代码编写和调试的难度。</p><p>尽管主进程到渲染进程的通信是单向的，但 Electron 提供了一种名为 &quot;ipcRenderer&quot; 的机制，允许渲染进程向主进程发送异步消息，然后主进程可以通过 &quot;ipcMain&quot; 监听这些消息并做出响应。这种机制允许渲染进程请求主进程执行特定的操作，同时通过限制通信方向来保持架构的稳定性和安全性。</p>',54)];p.render=function(s,e,p,o,c,r){return a(),n("div",null,t)};export{e as __pageData,p as default};
